    if (api_key[0] == '\0' || user_info[0] == '\0') {
        return 0;
    }

    /* Find an empty slot in the key store */
    for (i = 0; i < 50; i++) {
        if (key_store[i].key[0] == '\0') {
            empty_slot = i;
            break;
        }
    }

    /* No empty slot available */
    if (empty_slot == -1) {
        return 0;
    }

    /* Safely copy the API key (256 byte buffer) */
    if (safe_copy(key_store[empty_slot].key, api_key, sizeof(key_store[empty_slot].key)) != 0) {
        /* API key too long, clear any partial data and fail */
        key_store[empty_slot].key[0] = '\0';
        return 0;
    }

    /* Safely copy the user info (128 byte buffer) */
    if (safe_copy(key_store[empty_slot].user, user_info, sizeof(key_store[empty_slot].user)) != 0) {
        /* User info too long, clear any partial data and fail */
        key_store[empty_slot].key[0] = '\0';
        key_store[empty_slot].user[0] = '\0';
        return 0;
    }

    /* Initialize permissions to default (no permissions) */
    key_store[empty_slot].permissions = 0;

    /* Compute and return the hash of the API key */
    hash_value = compute_hash(api_key);

    /* Ensure hash is non-zero (0 is reserved for error indication) */
    if (hash_value == 0) {
        hash_value = 1;
    }

    return hash_value;
}
